local Widget = require "widgets/widget" local Text = require "widgets/text" local Spinner = require "widgets/spinner" local COLS = 0x2 local ROWS_PER_COL = 0x7 local function RefreshOptions(self) if not self.dycHoverText then local hoverText = self.root:AddChild(Text(BUTTONFONT, 0x16, " " )) self.dycHoverText = hoverText hoverText:SetHAlign(ANCHOR_LEFT) hoverText:SetVAlign(ANCHOR_TOP) hoverText:SetPosition(0x0, - 0xe6, 0x0) hoverText:SetRegionSize(0x320, 0x32) hoverText:EnableWordWrap(true) end local hoverText = self.dycHoverText local SetHoverText = function(str) str = str and string.gsub(str, "\n" , "" ) if hoverText.SetText then hoverText:SetText(str) else hoverText:SetString(str) end if hoverText.AnimateIn then hoverText:AnimateIn() end end if not self.dycOptions then self.dycOptions = {} if self.config and type(self.config) == "table" then for i, v in ipairs(self.config) do if v.name and v.options and (v.saved ~= nil or v.default ~= nil) then local hover = v.hover hover = hover and type(hover) == "string" and #hover > 0x0 and hover table.insert(self.dycOptions, {name = v.name, label = v.label, options = v.options, default = v.default, value = v.saved, hover = hover}) end end end end local options = self.dycOptions local focus = self:GetDeepestFocus() local old_column = focus and focus.column local old_idx = focus and focus.idx for k, v in pairs(self.optionwidgets) do v.root:Kill() end self.optionwidgets = {} self.left_spinners = {} self.right_spinners = {} for k = 0x1, ROWS_PER_COL * 0x2 do local idx = self.option_offset + k if options[idx] then local spin_options = {} for k, v in ipairs(options[idx].options) do local hover = v.hover hover = hover and type(hover) == "string" and #hover > 0x0 and hover table.insert(spin_options, {text = v.description, data = v.data, hover = hover}) end local opt = self.optionspanel:AddChild(Widget( "option" )) local spin_height = 0x32 local w = 0xdc local spinner = opt:AddChild(Spinner(spin_options, w, spin_height)) spinner:SetTextColour(0x0, 0x0, 0x0, 0x1) local default_value = options[idx].value if default_value == nil then default_value = options[idx].default end local ShowHover = function() self.dycHoveredWidget = spinner local hover = options[idx].hover local selectedOption = spinner.options[spinner.selectedIndex] local hover2 = selectedOption and selectedOption.hover SetHoverText((hover or "" )..(hover and hover2 and " " or "" )..(hover2 or " " )) end spinner.OnChanged = function(_, data) options[idx].value = data self:MakeDirty() ShowHover() end spinner:SetSelected(default_value) spinner:SetPosition(0x23, 0x0, 0x0) spinner.OnGainFocus = function() ShowHover() end spinner.OnLoseFocus = function() if self.dycHoveredWidget == spinner then SetHoverText( " " ) end end local spacing = 0x37 local label_width = 0xb4 local label = spinner:AddChild(Text(BUTTONFONT, 0x1e,(options[idx].label or options[idx].name) or STRINGS.UI.MODSSCREEN.UNKNOWN_MOD_CONFIG_SETTING)) label:SetPosition( - label_width / 0x2 - 0x69, 0x0, 0x0) label:SetRegionSize(label_width, 0x32) label:SetHAlign(ANCHOR_MIDDLE) if k <= ROWS_PER_COL then opt:SetPosition( - 0x9b,(ROWS_PER_COL - 0x1) * spacing * .5 - (k - 0x1) * spacing - 0xa, 0x0) table.insert(self.left_spinners, spinner) spinner.column = "left" spinner.idx = #self.left_spinners else opt:SetPosition(0x109,(ROWS_PER_COL - 0x1) * spacing * .5 - (k - 0x1 - ROWS_PER_COL) * spacing - 0xa, 0x0) table.insert(self.right_spinners, spinner) spinner.column = "right" spinner.idx = #self.right_spinners end table.insert(self.optionwidgets, {root = opt}) end end self:HookupFocusMoves() if old_column and old_idx then local list = old_column == "right" and self.right_spinners or self.left_spinners list[math.min(#list, old_idx)]:SetFocus() end end local function CollectSettings(self) if self.dycOptions then local settings = nil for i, v in pairs(self.dycOptions) do if not settings then settings = {} end table.insert(settings, {name = v.name, label = v.label, options = v.options, default = v.default, saved = v.value}) end return settings end end local function ChangeMCfgScr(self) self.dycOverrided = true self.CollectSettings = CollectSettings self.RefreshOptions = RefreshOptions self.optionspanel:SetPosition(0x0, 0x0) self:RefreshOptions() end return ChangeMCfgScr 